import java.util.ArrayList;
import java.util.Arrays;
import java.util.HashSet;
import java.util.LinkedHashSet;

public class Main {
    public static void main(String[] args) {
        ArrayList<Integer> nums = new ArrayList<>(Arrays.asList(3, 1, 4, 1, 5, 9, 2, 6, 5, 3));

        HashSet<Integer> unique = new HashSet<>(nums);
        System.out.println(unique.size());  // 7

        LinkedHashSet<Integer> ordered = new LinkedHashSet<>(nums);
        System.out.println(ordered);  // [3, 1, 4, 5, 9, 2, 6]
    }
}

